#include <stdio.h>
#include <stdlib.h>

#define MAX_NM 1000000  // N*M ≤ 10^6 fits in memory

int dr[4] = {0, 0, 1, -1};
int dc[4] = {1, -1, 0, 0};

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int n, m; scanf("%d %d", &n, &m);
        int **dist = (int**)malloc(n * sizeof(int*));
        int **mat = (int**)malloc(n * sizeof(int*));
        for (int i = 0; i < n; ++i) {
            mat[i] = (int*)malloc(m * sizeof(int));
            dist[i] = (int*)malloc(m * sizeof(int));
        }
        // queue of positions encoded as a single integer idx = r*m + c
        int *queue = (int*)malloc(n * m * sizeof(int));
        int front = 0, rear = 0;
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < m; ++j) {
                scanf("%d", &mat[i][j]);
                if (mat[i][j] == 0) {
                    dist[i][j] = 0;
                    queue[rear++] = i * m + j;
                } else {
                    dist[i][j] = -1; // unvisited
                }
            }
        }
        while (front < rear) {
            int idx = queue[front++];
            int r = idx / m;
            int c = idx % m;
            for (int k = 0; k < 4; ++k) {
                int nr = r + dr[k];
                int nc = c + dc[k];
                if (nr >= 0 && nr < n && nc >= 0 && nc < m && dist[nr][nc] == -1) {
                    dist[nr][nc] = dist[r][c] + 1;
                    queue[rear++] = nr * m + nc;
                }
            }
        }
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < m; ++j) {
                printf("%d", dist[i][j]);
                if (j + 1 < m) printf(" ");
            }
            printf("\n");
        }
        for (int i = 0; i < n; ++i) {
            free(mat[i]);
            free(dist[i]);
        }
        free(mat);
        free(dist);
        free(queue);
    }
    return 0;
}

