import sys
from collections import deque

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it)); m = int(next(it))
        mat = [[int(next(it)) for _ in range(m)] for _ in range(n)]
        dist = [[-1]*m for _ in range(n)]
        q = deque()
        for i in range(n):
            for j in range(m):
                if mat[i][j] == 0:
                    dist[i][j] = 0
                    q.append((i,j))
        dr = (0,0,1,-1)
        dc = (1,-1,0,0)
        while q:
            r,c = q.popleft()
            d = dist[r][c]
            for k in range(4):
                nr = r + dr[k]
                nc = c + dc[k]
                if 0 <= nr < n and 0 <= nc < m and dist[nr][nc] == -1:
                    dist[nr][nc] = d + 1
                    q.append((nr,nc))
        for row in dist:
            out_lines.append(' '.join(map(str,row)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

