        dist[i][j] = 0;
        queue.push([i, j]);
      }
    }
  }
  const dr = [0,0,1,-1];
  const dc = [1,-1,0,0];
  while (head < queue.length) {
    const [r,c] = queue[head++];
    const cur = dist[r][c];
